        assertEquals("user:alice", c.subject(), "sub=用户");
        assertEquals(agent.toUri(), c.actor(), "act=Agent");
        assertEquals(Set.of("c"), c.scopes(), "交集 {a,b,c}∩{b,c,d}∩{c,d} = {c}");
